#include <stdio.h>
#include <string.h>

int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    char A[N][1000001];
    for (int i = 0; i < N; i++) {
        scanf("%s", A[i]);
    }
    for (int i = 0; i < Q; i++) {
        int L, R;
        char X[1000001];
        scanf("%d %d %s", &L, &R, X);
        int max_val = -1;
        int max_index = -1;
        for (int j = L - 1; j < R; j++) {
            int val = 0;
            for (int k = 0; k < strlen(A[j]) && k < strlen(X); k++) {
                if (A[j][k] != X[k]) {
                    val += (1 << (strlen(A[j]) - k - 1));
                }
            }
            if (val > max_val) {
                max_val = val;
                max_index = j + 1;
            }
        }
        printf("%d\n", max_index);
    }
    return 0;
}

