import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int Q = sc.nextInt();
        String[] A = new String[N];
        for (int i = 0; i < N; i++) {
            A[i] = sc.next();
        }
        for (int i = 0; i < Q; i++) {
            int L = sc.nextInt();
            int R = sc.nextInt();
            String X = sc.next();
            int max_val = -1;
            int max_index = -1;
            for (int j = L - 1; j < R; j++) {
                int val = 0;
                for (int k = 0; k < A[j].length() && k < X.length(); k++) {
                    if (A[j].charAt(k) != X.charAt(k)) {
                        val += (1 << (A[j].length() - k - 1));
                    }
                }
                if (val > max_val) {
                    max_val = val;
                    max_index = j + 1;
                }
            }
            System.out.println(max_index);
        }
    }
}

